```plantuml
@startuml
class User {
  -id: integer
  -name: string
  +getId(): integer
  +getName(): string
}

class Employee {
  -position: string
  +getPosition(): string
}

class Owner {
  -balance: integer
  +getBalance(): integer
}

interface StoreInterface {
  +getStoreName(): string
  +getOwnerName(): string
  +getEmployees(): []Employee
}

class CakeStore {
  -storeName: string
  -owner: Owner
  -employees: []Employee
}

class CoffeeStore {
  -storeName: string
  -owner: Owner
  -employees: []Employee
}

class MainStore {
  +storeInterface: StoreInterface
}

User <|-- Employee
User <|-- Owner

Employee --o CakeStore
Employee --o CoffeeStore

Owner --* CakeStore
Owner --* CoffeeStore

StoreInterface <|.. CakeStore
StoreInterface <|.. CoffeeStore

StoreInterface <-- MainStore

@enduml
```
